link.script:
{
    "@context": "https://schema.org",
    "@type": "FAQPage",
    "mainEntity": [
        {
            "@type": "Question",
            "name": "How do I conduct a test using tes?",
            "acceptedAnswer": {
                "@type": "Answer",
                "text": "To conduct a test using tes, first sign up on their platform and navigate to the 'Create Test' section. Follow the prompts to input your test parameters, such as subject, difficulty, and duration. Once set, you can distribute the test link to participants and monitor their progress in real-time."
            }
        },
        {
            "@type": "Question",
            "name": "How long does it take to complete a test on tes?",
            "acceptedAnswer": {
                "@type": "Answer",
                "text": "The time to complete a test on tes varies depending on the test type and settings. Typically, a standard test can be completed in 30 to 60 minutes, with immediate results available upon completion."
            }
        },
        {
            "@type": "Question",
            "name": "How much does it cost to use tes for testing?",
            "acceptedAnswer": {
                "@type": "Answer",
                "text": "Tes offers a variety of pricing plans starting from $10 per month for individual users. There are also enterprise packages available, which include advanced features and customization options, starting at $100 per month."
            }
        },
        {
            "@type": "Question",
            "name": "What is the difference between the free and paid versions of tes?",
            "acceptedAnswer": {
                "@type": "Answer",
                "text": "The free version of tes allows users to create basic tests with limited customization and reporting features. In contrast, the paid version provides access to advanced analytics, personalized support, and the ability to host unlimited tests, making it ideal for professional and educational purposes."
            }
        }
    ]
}
